class Solution:
    def mergeCharacters(self, s: str, k: int) -> str:
        # Independent approach: literally simulate the rule as stated -- repeatedly
        # find the leftmost close pair and delete the right character, restarting
        # the scan from the beginning after every merge, until no merge is possible.
        chars = list(s)
        while True:
            n = len(chars)
            merged = False
            for i in range(n):
                limit = min(i + k, n - 1)
                for j in range(i + 1, limit + 1):
                    if chars[j] == chars[i]:
                        del chars[j]
                        merged = True
                        break
                if merged:
                    break
            if not merged:
                break
        return ''.join(chars)

