class Solution:
    def mergeCharacters(self, s: str, k: int) -> str:
        stack = []
        for c in s:
            j = len(stack) - 1
            skip = False
            while j >= 0 and len(stack) - j <= k:
                if stack[j] == c:
                    skip = True
                    break
                j -= 1
            if not skip:
                stack.append(c)
        return ''.join(stack)

