var mergeCharacters = function(s, k) {
    const stack = [];
    for (const c of s) {
        let j = stack.length - 1;
        let skip = false;
        while (j >= 0 && stack.length - j <= k) {
            if (stack[j] === c) {
                skip = true;
                break;
            }
            j -= 1;
        }
        if (!skip) {
            stack.push(c);
        }
    }
    return stack.join('');
};
